const express = require("express");
const router = express.Router();
const db = require("../db/database");
const multer = require("multer");

const upload = multer({ dest: "uploads/" });

// ================= GET
router.get("/", (req, res) => {
  db.all("SELECT * FROM payments ORDER BY id DESC", [], (err, rows) => {
    if (err) return res.status(500).json(err);
    res.json(rows);
  });
});

// ================= POST (NO DUPLICATE SAFE)
router.post("/", upload.single("invoice"), (req, res) => {

  const data = req.body;

  db.run(
    `INSERT INTO payments (
      title, clientName, projectName,
      milestoneName,
      totalAmount, paidAmount, pendingAmount,
      paymentDate, dueDate,
      invoiceFile
    ) VALUES (?,?,?,?,?,?,?,?,?,?)`,
    [
      data.title,
      data.clientName,
      data.projectName,
      data.milestoneName,
      data.totalAmount,
      data.paidAmount,
      data.pendingAmount,
      data.paymentDate,
      data.dueDate,
      req.file ? req.file.filename : null
    ],
    function (err) {
      if (err) return res.status(500).json(err);
      res.json({ id: this.lastID });
    }
  );
});

// ================= UPDATE
router.put("/:id", upload.single("invoice"), (req, res) => {

  const data = req.body;

  db.run(
    `UPDATE payments SET
      title=?, clientName=?, projectName=?,
      milestoneName=?,
      totalAmount=?, paidAmount=?, pendingAmount=?,
      paymentDate=?, dueDate=?
     WHERE id=?`,
    [
      data.title,
      data.clientName,
      data.projectName,
      data.milestoneName,
      data.totalAmount,
      data.paidAmount,
      data.pendingAmount,
      data.paymentDate,
      data.dueDate,
      req.params.id
    ],
    function (err) {
      if (err) return res.status(500).json(err);
      res.json({ message: "Updated" });
    }
  );
});

// ================= DELETE
router.delete("/:id", (req, res) => {
  db.run("DELETE FROM payments WHERE id=?", [req.params.id], function (err) {
    if (err) return res.status(500).json(err);
    res.json({ message: "Deleted" });
  });
});

module.exports = router;
